#!/usr/bin/env python3
"""Inject Modern Hamlet expansion portraits (a936-a950) into assets/assets.json. Idempotent.
Usage (from the repo root, same folder as build.py):
    python3 apply_modern_hamlet_art.py
Safe to run repeatedly; only writes assets that are missing or changed.
"""
import json, os, sys
ROOT = os.path.dirname(os.path.abspath(__file__))
ASSETS = os.path.join(ROOT, "assets", "assets.json")

# 15 Modern Hamlet character portraits, raw base64 (JPEG), keyed by asset id.
ART = {
    "a951": "",
    "a936": "",
    "a937": "",
    "a938": "",
    "a939": "",
    "a940": "",
    "a941": "",
    "a942": "",
    "a943": "",
    "a944": "",
    "a945": "",
    "a946": "",
    "a947": "",
    "a948": "",
    "a949": "",
    "a950": "",
}

def main():
    if not os.path.isfile(ASSETS):
        sys.exit("ERROR: assets/assets.json not found. Run this from the repo root (next to build.py).")
    try:
        data = json.load(open(ASSETS, encoding="utf-8"))
    except Exception as e:
        sys.exit(f"ERROR reading assets.json: {e}")
    if not isinstance(data, dict):
        sys.exit("ERROR: assets.json is not the expected flat {'aNNN': '<base64>'} object.")
    added = skipped = 0
    for k, v in ART.items():
        if data.get(k) == v:
            skipped += 1
        else:
            data[k] = v; added += 1
    json.dump(data, open(ASSETS, "w", encoding="utf-8"))
    print(f"Modern Hamlet portraits + deck box: {added} written, {skipped} already present (a936-a951).")
    print("Next: ensure game.src.html has the HAMLET_MODERN_IMG map (see the wiring blueprint), then run build.py.")

if __name__ == "__main__":
    main()
